    "ai.widget.msg1.user": "\u0414\u0430\u0439\u0442\u0435 \u0441\u0432\u043e\u0434\u043a\u0443 \u043c\u043e\u0435\u0433\u043e \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0435\u0433\u043e \u0432\u0438\u0437\u0438\u0442\u0430.",
    "ai.widget.msg1.ai":  "\u0412\u0430\u0448 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0439 \u0432\u0438\u0437\u0438\u0442 \u0431\u044b\u043b \u043e\u043a\u043e\u043b\u043e \u0433\u043e\u0434\u0430 \u043d\u0430\u0437\u0430\u0434. \u0412\u044b \u0441\u043e\u043e\u0431\u0449\u0430\u043b\u0438 \u043e \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u044e\u0449\u0438\u0445\u0441\u044f \u0433\u043e\u043b\u043e\u0432\u043d\u044b\u0445 \u0431\u043e\u043b\u044f\u0445 \u0438 \u043b\u0451\u0433\u043a\u0438\u0445 \u0441\u0438\u043c\u043f\u0442\u043e\u043c\u0430\u0445 \u0433\u0440\u0438\u043f\u043f\u0430. \u0412\u0440\u0430\u0447 \u0440\u0435\u043a\u043e\u043c\u0435\u043d\u0434\u043e\u0432\u0430\u043b \u043e\u0442\u0434\u044b\u0445 \u0438 \u043d\u0430\u0437\u043d\u0430\u0447\u0438\u043b \u0438\u0431\u0443\u043f\u0440\u043e\u0444\u0435\u043d. \u041f\u043e\u0432\u0442\u043e\u0440\u043d\u044b\u0439 \u0432\u0438\u0437\u0438\u0442 \u043d\u0430\u0437\u043d\u0430\u0447\u0435\u043d \u043d\u0435 \u0431\u044b\u043b.",
    "ai.widget.msg2.user": "\u0421\u0440\u0430\u0432\u043d\u0438\u0442\u0435 \u043c\u043e\u0439 \u0442\u0435\u043a\u0443\u0449\u0438\u0439 \u0430\u043d\u0430\u043b\u0438\u0437 \u043a\u0440\u043e\u0432\u0438 \u0441 \u043f\u0440\u0435\u0434\u044b\u0434\u0443\u0449\u0438\u043c\u0438 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0430\u043c\u0438.",
    "ai.widget.msg2.ai":  "\u0423\u0440\u043e\u0432\u0435\u043d\u044c \u0436\u0435\u043b\u0435\u0437\u0430 \u0443\u043b\u0443\u0447\u0448\u0438\u043b\u0441\u044f \u043d\u0430 12%. \u0425\u043e\u043b\u0435\u0441\u0442\u0435\u0440\u0438\u043d \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u043f\u043e\u0432\u044b\u0448\u0435\u043d \u043f\u043e \u0441\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u044e \u0441 \u043f\u0440\u043e\u0448\u043b\u044b\u043c \u0440\u0430\u0437\u043e\u043c \u2014 198 \u043f\u0440\u043e\u0442\u0438\u0432 181\u00a0\u043c\u0433/\u0434\u043b. \u0412\u0441\u0435 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u0438 \u0432 \u043d\u043e\u0440\u043c\u0435.",
    "ai.widget.msg3.user": "\u041a\u0430\u043a \u0437\u0432\u0430\u043b\u0438 \u0441\u0442\u043e\u043c\u0430\u0442\u043e\u043b\u043e\u0433\u0430, \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u044f \u043f\u043e\u0441\u0435\u0449\u0430\u043b \u0432 \u043f\u0440\u043e\u0448\u043b\u043e\u043c \u0433\u043e\u0434\u0443?",
    "ai.widget.msg3.ai":  "\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u0441\u043a\u043e\u0440\u043e \u043f\u043e\u0441\u0435\u0442\u0438\u0442\u044c \u043a\u043b\u0438\u043d\u0438\u043a\u0443 \u2014 \u043d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0441\u0438\u043c\u043f\u0442\u043e\u043c\u044b \u043c\u043e\u0433\u0443\u0442 \u0441\u0442\u0430\u0442\u044c \u0441\u0435\u0440\u044c\u0451\u0437\u043d\u0435\u0435. \u041c\u043e\u0433\u0443 \u043b\u0438 \u044f \u043f\u043e\u043c\u043e\u0447\u044c \u0432\u0430\u043c \u043d\u0430\u0439\u0442\u0438 \u0441\u0432\u043e\u0431\u043e\u0434\u043d\u043e\u0435 \u0432\u0440\u0435\u043c\u044f \u0443 \u0431\u043b\u0438\u0436\u0430\u0439\u0448\u0435\u0433\u043e \u0432\u0440\u0430\u0447\u0430?",

